import math
from typing import Callable, List, Tuple

def sieve_of_eratosthenes(limit: int) -> List[bool]:
    """
    Generates a boolean list indicating primality for numbers up to a given limit
    using the Sieve of Eratosthenes algorithm.

    The Sieve of Eratosthenes is an efficient algorithm for finding all prime
    numbers up to any given limit. It works by iteratively marking as composite
    (i.e., not prime) the multiples of each prime, starting with the first prime
    number, 2. The unmarked numbers remaining are prime.

    Args:
        limit: An integer representing the upper bound (inclusive) for finding primes.
               Numbers from 0 to `limit` will be checked. Must be non-negative.

    Returns:
        A list of booleans, `is_prime`, where `is_prime[i]` is True if `i` is a
        prime number, and False otherwise. The list has `limit + 1` elements.

    Raises:
        ValueError: If `limit` is negative.

    Examples:
        >>> sieve_of_eratosthenes(10)
        [False, False, True, True, False, True, False, True, False, False, False]
        # Explanation:
        # is_prime[0] = False (not prime)
        # is_prime[1] = False (not prime)
        # is_prime[2] = True  (prime)
        # is_prime[3] = True  (prime)
        # is_prime[4] = False (2*2)
        # is_prime[5] = True  (prime)
        # is_prime[6] = False (2*3)
        # is_prime[7] = True  (prime)
        # is_prime[8] = False (2*4)
        # is_prime[9] = False (3*3)
        # is_prime[10] = False (2*5)
    """
    if limit < 0:
        raise ValueError("Limit must be a non-negative integer.")

    is_prime: List[bool] = [True] * (limit + 1)
    if limit >= 0:
        is_prime[0] = False  # 0 is not prime
    if limit >= 1:
        is_prime[1] = False  # 1 is not prime

    # Iterate from 2 up to sqrt(limit)
    # Any composite number n must have at least one prime factor less than or equal to sqrt(n)
    for p in range(2, int(math.sqrt(limit)) + 1):
        # If p is prime (not marked False yet)
        if is_prime[p]:
            # Mark all multiples of p as not prime.
            # We can start from p*p because any multiple k*p where k < p would have
            # already been marked by a smaller prime factor than p.
            for multiple in range(p * p, limit + 1, p):
                is_prime[multiple] = False
    return is_prime

