def binary_search_first_true(
    low: int, high: int, predicate: Callable[[int], bool]
) -> int:
    """
    Performs a binary search to find the smallest integer `x` within a given
    range `[low, high]` for which a `predicate(x)` evaluates to True.

    This function is useful when searching for a threshold value where a condition
    switches from False to True. The `predicate` function must exhibit a
    monotonic property: if `predicate(x)` is True, then `predicate(y)` must also
    be True for all `y > x`. Conversely, if `predicate(x)` is False, then
    `predicate(y)` must also be False for all `y < x`. The typical pattern is
    `F F F ... T T T`.

    Args:
        low: The lower bound (inclusive) of the search range.
        high: The upper bound (inclusive) of the search range.
        predicate: A callable (function or lambda) that takes an integer `x`
                   and returns a boolean. It should be monotonically non-decreasing.

    Returns:
        The smallest integer `x` in `[low, high]` such that `predicate(x)` is True.
        Returns `high + 1` if no such `x` exists in the range `[low, high]`
        (meaning all values in `[low, high]` result in False for the predicate,
        or the range is empty). This `high + 1` value indicates that the "first true"
        value is effectively "out of bounds" on the right. If the first true value
        is `low`, it returns `low`.

    Examples:
        # Predicate: `x >= 6` (monotonic non-decreasing: F F F F F F T T T T T)
        # Search range [0, 10]
        >>> def is_sufficient(x: int) -> bool:
        ...     return x >= 6
        >>> binary_search_first_true(0, 10, is_sufficient)
        6

        # All values in the range are False (e.g., search [0, 5] for `x >= 6`)
        >>> binary_search_first_true(0, 5, is_sufficient)
        6 # (high + 1, indicating no value in [0, 5] satisfies the predicate)

        # All values in the range are True (e.g., search [0, 10] for `x >= 0`)
        >>> binary_search_first_true(0, 10, lambda x: x >= 0)
        0

        # Empty range (low > high)
        >>> binary_search_first_true(5, 0, lambda x: True)
        1 # (high + 1, as if no value found)
    """
    ans = high + 1  # Initialize with a value indicating 'not found'
    # This also serves as the potential answer if all elements are false or range is empty.

    while low <= high:
        mid = low + (high - low) // 2
        if predicate(mid):
            ans = mid  # mid could be the answer, try to find an even smaller one
            high = mid - 1
        else:
            low = mid + 1
    return ans

